function sha256(ascii) {
  function rightRotate(value, amount) { return (value >>> amount) | (value << (32 - amount)); }
  const mathPow = Math.pow, maxWord = mathPow(2, 32), lengthProperty = 'length';
  let i, j, result = '';
  const words = [], asciiBitLength = ascii[lengthProperty] * 8;
  let hash = [], k = [], primeCounter = k[lengthProperty];
  const isComposite = {};
  for (let candidate = 2; primeCounter < 64; candidate++) {
    if (!isComposite[candidate]) {
      for (i = 0; i < 313; i += candidate) isComposite[i] = candidate;
      hash[primeCounter] = (mathPow(candidate, 0.5) * maxWord) | 0;
      k[primeCounter++] = (mathPow(candidate, 1/3) * maxWord) | 0;
    }
  }
  ascii += '\x80';
  while (ascii[lengthProperty] % 64 - 56) ascii += '\x00';
  for (i = 0; i < ascii[lengthProperty]; i++) {
    j = ascii.charCodeAt(i);
    if (j >> 8) return;
    words[i >> 2] |= j << ((3 - i) % 4) * 8;
  }
  words[words[lengthProperty]] = (asciiBitLength / maxWord) | 0;
  words[words[lengthProperty]] = asciiBitLength;
  for (j = 0; j < words[lengthProperty]; ) {
    const w = words.slice(j, j += 16), oldHash = hash.slice(0);
    for (i = 0; i < 64; i++) {
      const w15 = w[i - 15], w2 = w[i - 2];
      const a = hash[0], e = hash[4];
      const temp1 = hash[7]
        + (rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25))
        + ((e & hash[5]) ^ (~e & hash[6])) + k[i]
        + (w[i] = (i < 16) ? w[i] : (w[i-16]
          + (rightRotate(w15,7) ^ rightRotate(w15,18) ^ (w15 >>> 3))
          + w[i-7] + (rightRotate(w2,17) ^ rightRotate(w2,19) ^ (w2 >>> 10))) | 0);
      const temp2 = (rightRotate(a,2) ^ rightRotate(a,13) ^ rightRotate(a,22))
        + ((a & hash[1]) ^ (a & hash[2]) ^ (hash[1] & hash[2]));
      hash = [(temp1 + temp2) | 0].concat(hash);
      hash[4] = (hash[4] + temp1) | 0;
      hash.length = 8;
    }
    hash = hash.map((x, i) => (x + oldHash[i]) | 0);
  }
  for (i = 0; i < 8; i++)
    for (j = 3; j + 1; j--) { const b = (hash[i] >> (j * 8)) & 255; result += (b < 16 ? '0' : '') + b.toString(16); }
  return result;
}
function hashField(val) { if (!val) return ''; return sha256(String(val).trim().toLowerCase()); }
function str(val) { if (!val) return ''; if (typeof val === 'object') return ''; return String(val).trim(); }

// Walidacja fbc - odrzuca wartosci starsze niz 90 dni
function isValidFbc(fbc) {
  if (!fbc || typeof fbc !== 'string') return false;
  const parts = fbc.split('.');
  if (parts.length < 4) return false;
  const ts = parseInt(parts[2], 10);
  if (!ts || isNaN(ts)) return false;
  return (Date.now() - ts) < (90 * 24 * 60 * 60 * 1000);
}

function generateFbp() {
  return 'fb.1.' + Date.now() + '.' + Math.floor(Math.random() * 2147483647);
}

const body = $input.first().json.body || $input.first().json;
const headers = $input.first().json.headers || {};

const imieRaw = body.imie || {};
let fullName = '';
if (typeof imieRaw === 'object') {
  const fn = str(imieRaw.first_name);
  const ln = str(imieRaw.last_name);
  fullName = (fn + ' ' + ln).trim();
} else {
  fullName = str(imieRaw);
}
if (!fullName && body.__submission && body.__submission.user_inputs) {
  fullName = str(body.__submission.user_inputs.imie);
}

const nameParts = fullName.split(' ');
const firstName = nameParts[0] || '';
const lastName  = nameParts.slice(1).join(' ') || '';

const telefon    = str(body.telefon);
const email      = str(body.email).toLowerCase();
const opis       = str(body.opis);
const inwestycja = str(body.inwestycja);
const apartament = str(body.apartament_id);

let phoneCleaned = telefon.replace(/[\s\-().]/g, '');
if (phoneCleaned && !phoneCleaned.startsWith('+')) {
  phoneCleaned = phoneCleaned.startsWith('48') ? '+' + phoneCleaned : '+48' + phoneCleaned;
}

const emailHash     = hashField(email);
const phoneHash     = hashField(phoneCleaned);
const firstNameHash = hashField(firstName);
const lastNameHash  = hashField(lastName);

const eventId    = body.event_id    || ('lead_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8));
const gaClientId  = body.ga_client_id || '';
const gaSessionId = body.ga_session_id || '';

// Sygnaly przegladarki - poprawiaja EMQ i pokrycie
const userAgent = body.user_agent || headers['user-agent'] || '';
const clientIp  = headers['x-real-ip'] || headers['x-forwarded-for'] || body.client_ip || '';
const fbpRaw    = body.fbp || '';
const fbp       = fbpRaw || generateFbp();
const fbcRaw    = body.fbc || '';
const fbc       = isValidFbc(fbcRaw) ? fbcRaw : '';

// external_id: email lub telefon (hashed)
const externalIdRaw = email ? email.toLowerCase().trim() : phoneCleaned;
const externalId    = externalIdRaw ? hashField(externalIdRaw) : '';

const userData = {
  em: emailHash || undefined,
  ph: phoneHash || undefined,
  fn: firstNameHash || undefined,
  ln: lastNameHash || undefined,
  external_id: externalId || undefined,
  fbp: fbp || undefined,
  fbc: fbc || undefined,
  client_ip_address: clientIp || undefined,
  client_user_agent: userAgent || undefined
};
Object.keys(userData).forEach(k => { if (!userData[k]) delete userData[k]; });

const capiData = {
  data: [{
    event_name: 'Lead',
    event_time: Math.floor(Date.now() / 1000),
    event_id: eventId,
    action_source: 'website',
    event_source_url: 'https://maltaview.pl',
    user_data: userData,
    custom_data: {
      content_name: inwestycja || 'Formularz — Zapytaj o Apartament'
    }
  }]
};

return [{
  json: {
    firstName, lastName, fullName, email, telefon, phoneCleaned,
    opis, inwestycja, apartament,
    eventId, gaClientId, gaSessionId,
    emailHash, phoneHash, firstNameHash, lastNameHash,
    capiData
  }
}];

